                // We only rely on option 1.
                option2_ok = false;
            }

            if (!option1_ok && !option2_ok) {
                return false; // Cannot achieve target parity T for index i
            }
        }
        return true;
    };

    // Check if all can be even (T=0) OR all can be odd (T=1)
    return checkTargetParity(0) || checkTargetParity(1);
