function solve(nums1) {
    const n = nums1.length;

    // Helper function to check if all elements in an array are of the same parity
    const checkParity = (arr) => {
        if (arr.length === 0) return true;
        const parity = arr[0] % 2; // 0 for even, 1 for odd
        for (let i = 1; i < arr.length; i++) {
            if ((arr[i] % 2 + 2) % 2 !== parity) {
                return false;
            }
        }
        return true;
    };

    // We need to check if *any* valid assignment results in all odd or all even.
    // Since n is small (<= 100), we might consider dynamic programming or checking constraints.
    // The choice for each nums2[i] depends on the choices made for others (for subtraction).

    // Let's analyze the constraints on parity for nums2[i] based on nums1[i] and nums1[j].
    // 1. nums2[i] = nums1[i] -> Parity of nums2[i] is parity(nums1[i]).
    // 2. nums2[i] = nums1[i] - nums1[j] -> Parity of nums2[i] is parity(nums1[i] - nums1[j]) = parity(nums1[i]) XOR parity(nums1[j]).

    // Let P_i be the parity of nums1[i] (0 for even, 1 for odd).

    // If we fix the required target parity T (0 for even, 1 for odd) for all nums2[i],
    // for each i, we need to find a choice such that nums2[i] % 2 == T.

    // Case 1: Target Parity T = 0 (All Even)
    const canBeAllEven = () => {
        // For each i, can we make nums2[i] even?
        for (let i = 0; i < n; i++) {
            const P_i = nums1[i] % 2;

            // Option 1: nums2[i] = nums1[i]
            if (P_i === 0) continue; // If P_i is 1 (odd), this choice fails for T=0.

            // Option 2: nums2[i] = nums1[i] - nums1[j]
            // We need P_i XOR P_j = 0, which means P_j must equal P_i.
            // If P_i = 1 (odd), we need P_j = 1 (odd) for some j != i.
            if (P_i === 1) {
                let foundOddJ = false;
                for (let j = 0; j < n; j++) {
                    if (i !== j && nums1[j] % 2 !== 0) { // nums1[j] is odd
                        foundOddJ = true;
                        break;
                    }
                }
                if (!foundOddJ) {
                    return false; // Cannot make nums2[i] even if nums1[i] is odd and no other odd number exists.
                }
            }
        }
        return true;
    };

    // Case 2: Target Parity T = 1 (All Odd)
    const canBeAllOdd = () => {
        // For each i, can we make nums2[i] odd?
        for (let i = 0; i < n; i++) {
            const P_i = nums1[i] % 2;

            // Option 1: nums2[i] = nums1[i]
            if (P_i === 1) continue; // If P_i is 0 (even), this choice fails for T=1.

            // Option 2: nums2[i] = nums1[i] - nums1[j]
            // We need P_i XOR P_j = 1, which means P_j must be different from P_i.
            // If P_i = 0 (even), we need P_j = 1 (odd) for some j != i.
