    // If this holds for T=0, we are done. If this holds for T=1, we are done.

    // Re-evaluating Case 1 (Target T=0, Even):
    // For a fixed i:
    //   Can we make nums2[i] even?
    //   1. nums1[i] is even? YES.
    //   2. nums1[i] is odd? YES, if there exists j!=i such that nums1[j] is odd (Odd - Odd = Even).

    const checkTargetParity = (T) => {
        for (let i = 0; i < n; i++) {
            const P_i = nums1[i] % 2;

            // Check Option 1: nums2[i] = nums1[i]
            const option1_ok = (P_i === T);

            // Check Option 2: nums2[i] = nums1[i] - nums1[j]
            // We need P_i XOR P_j = T, or P_j = P_i XOR T.
            const required_P_j = P_i ^ T;

            let option2_ok = false;
            if (n > 1) {
                for (let j = 0; j < n; j++) {
                    if (i !== j && (nums1[j] % 2 === required_P_j)) {
